#include <stdio.h>
#include <math.h>

static int max(int a, int b) { return a > b ? a : b; }
static int min(int a, int b) { return a < b ? a : b; }

static int minimax_impl(int depth, int nodeIndex, int isMax, int scores[], int h) {
    if (depth == h)
        return scores[nodeIndex];

    if (isMax)
        return max(minimax_impl(depth + 1, nodeIndex * 2, 0, scores, h),
                   minimax_impl(depth + 1, nodeIndex * 2 + 1, 0, scores, h));
    else
        return min(minimax_impl(depth + 1, nodeIndex * 2, 1, scores, h),
                   minimax_impl(depth + 1, nodeIndex * 2 + 1, 1, scores, h));
}

static int log2_int(int n) {
    return (n == 1) ? 0 : 1 + log2_int(n / 2);
}

int minimax(int scores[], int depth, int isMax) {
    if (depth < 0) {
        return 0;
    }
    return minimax_impl(0, 0, isMax, scores, depth);
}

int main() {
    int scores[] = {3, 5, 2, 9, 12, 5, 23, 23};
    int n = sizeof(scores) / sizeof(scores[0]);
    int h = log2_int(n);
    int result = minimax(scores, h, 1);
    printf("The optimal value is: %d\n", result);
    return 0;
}

#include <algorithm>
#include <vector>

namespace {
int minimax_impl(int depth, int node_index, bool is_max, const std::vector<int>& scores, int max_depth) {
    if (depth == max_depth) {
        return scores[node_index];
    }

    int left = minimax_impl(depth + 1, node_index * 2, !is_max, scores, max_depth);
    int right = minimax_impl(depth + 1, node_index * 2 + 1, !is_max, scores, max_depth);
    return is_max ? std::max(left, right) : std::min(left, right);
}
}  // namespace

int minimax(const std::vector<int>& tree_values, int depth, bool is_maximizing) {
    if (tree_values.empty()) {
        return 0;
    }
    if (depth <= 0 || tree_values.size() == 1) {
        return tree_values.front();
    }

    std::vector<int> padded = tree_values;
    int leaf_count = 1;
    while (leaf_count < static_cast<int>(padded.size())) {
        leaf_count <<= 1;
    }
    padded.resize(leaf_count, padded.back());

    return minimax_impl(0, 0, is_maximizing, padded, depth);
}

using System;

class Minimax
{
    static int MinimaxAlgo(int depth, int nodeIndex, bool isMax, int[] scores, int h)
    {
        if (depth == h)
            return scores[nodeIndex];

        if (isMax)
            return Math.Max(
                MinimaxAlgo(depth + 1, nodeIndex * 2, false, scores, h),
                MinimaxAlgo(depth + 1, nodeIndex * 2 + 1, false, scores, h));
        else
            return Math.Min(
                MinimaxAlgo(depth + 1, nodeIndex * 2, true, scores, h),
                MinimaxAlgo(depth + 1, nodeIndex * 2 + 1, true, scores, h));
    }

    static void Main(string[] args)
    {
        int[] scores = { 3, 5, 2, 9, 12, 5, 23, 23 };
        int h = (int)(Math.Log(scores.Length) / Math.Log(2));
        int result = MinimaxAlgo(0, 0, true, scores, h);
        Console.WriteLine("The optimal value is: " + result);
    }
}

package minimax

// Minimax for games with binary actions at each node
// graph[nodeID] contains the next game states v from game state nodeID
func Minimax(nodeID int, graph map[int][]int, scores map[int]int, isMax bool) int {

	if isMax {
		// return max

		fnd := false
		ret := 0

		for _, v := range graph[nodeID] {
			cur := Minimax(v, graph, scores, false)
			if !fnd {
				ret = cur
				fnd = true
			}

			if cur > ret {
				ret = cur
			}
		}

		if !fnd {
			// leaf node of game graph
			ret = scores[nodeID]
		}

		return ret
	}

	// return min
	fnd := false
	ret := 0

	for _, v := range graph[nodeID] {
		cur := Minimax(v, graph, scores, false)
		if !fnd {
			ret = cur
			fnd = true
		}

		if cur < ret {
			ret = cur
		}
	}

	if !fnd {
		// leaf node of game graph
		ret = scores[nodeID]
	}

	return ret
}

